 fs/ext4/file.c        |  3 ++-
 fs/iomap/direct-io.c  | 16 +++++++++++++---
 fs/iomap/trace.h      |  3 ++-
 fs/ntfs/file.c        |  4 ++--
 fs/xfs/xfs_file.c     |  2 +-
 include/linux/iomap.h |  8 ++++++++
 7 files changed, 30 insertions(+), 10 deletions(-)

